// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
#define MAX_N 32
#define MAX_WORD_LENGTH 4
#define GRID_SIZE 4

char grid[GRID_SIZE][GRID_SIZE];
char words[MAX_N][MAX_WORD_LENGTH + 1];
int n;

void printGrid() {
    for (int i = 0; i < GRID_SIZE; i++) {
        for (int j = 0; j < GRID_SIZE; j++) {
            printf("%c", grid[i][j]);
        }
        printf("\n");
    }
}

int canPlaceWord(int wordIndex, int row, int col, int direction) {
    if (direction == 0) { // horizontal
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            if (col + i >= GRID_SIZE || grid[row][col + i] != words[wordIndex][i] && grid[row][col + i] != '\0') {
                return 0;
            }
        }
    } else { // vertical
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            if (row + i >= GRID_SIZE || grid[row + i][col] != words[wordIndex][i] && grid[row + i][col] != '\0') {
                return 0;
            }
        }
    }
    return 1;
}

void placeWord(int wordIndex, int row, int col, int direction) {
    if (direction == 0) { // horizontal
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            grid[row][col + i] = words[wordIndex][i];
        }
    } else { // vertical
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            grid[row + i][col] = words[wordIndex][i];
        }
    }
}

void removeWord(int wordIndex, int row, int col, int direction) {
    if (direction == 0) { // horizontal
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            grid[row][col + i] = '\0';
        }
    } else { // vertical
        for (int i = 0; i < MAX_WORD_LENGTH; i++) {
            grid[row + i][col] = '\0';
        }
    }
}

int backtrack(int wordIndex) {
    if (wordIndex == n) {
        printGrid();
        return 1;
    }
    for (int row = 0; row < GRID_SIZE; row++) {
        for (int col = 0; col < GRID_SIZE; col++) {
            for (int direction = 0; direction < 2; direction++) {
                if (canPlaceWord(wordIndex, row, col, direction)) {
                    placeWord(wordIndex, row, col, direction);
                    if (backtrack(wordIndex + 1)) {
                        return 1;
                    }
                    removeWord(wordIndex, row, col, direction);
                }
            }
        }
    }
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            scanf("%s", words[i]);
        }
        for (int i = 0; i < GRID_SIZE; i++) {
            for (int j = 0; j < GRID_SIZE; j++) {
                grid[i][j] = '\0';
            }
        }
        if (!backtrack(0)) {
            printf("grid\nsnot\nposs\nible\n");
        }
        printf("\n");
    }
    return 0;
}

